/**
 * Inline SVG icons for each payment method.
 *
 * Self-contained — no external CDN or Font Awesome dependency.
 * Card brand SVGs sourced from aaronfagan/svg-credit-card-payment-icons (flat-rounded).
 * Apple Pay & Google Pay use custom card-style SVGs.
 */

defined( 'ABSPATH' ) || exit;

class Kidi_AP_Icons {

    /**
     * Return SVG markup for a given payment method key.
     *
     * @param string $key Payment method slug.
     * @return string SVG markup or empty string.
     */
    public static function get( $key ) {
        $icons = self::all();
        return isset( $icons[ $key ] ) ? $icons[ $key ] : '';
    }

    /**
     * All available payment method keys with labels.
     *
     * @return array<string, string> key => human-readable label.
     */
    public static function labels() {
        return array(
            'visa'       => 'Visa',
            'mastercard' => 'Mastercard',
            'amex'       => 'American Express',
            'paypal'     => 'PayPal',
            'applepay'   => 'Apple Pay',
            'googlepay'  => 'Google Pay',
        );
    }

    /**
     * All SVG icons keyed by payment method slug.
     *
     * @return array<string, string>
     */
    public static function all() {
        return array(
            'visa'       => self::visa(),
            'mastercard' => self::mastercard(),
            'amex'       => self::amex(),
            'paypal'     => self::paypal(),
            'applepay'   => self::applepay(),
            'googlepay'  => self::googlepay(),
        );
    }

